{
  "module": "01-layout.md",
  "group": "01 — Layout & Navigation",
  "apiCount": 10,
  "apis": [
    {
      "name": "Flex",
      "purpose": "弹性布局容器，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的容器，可设置子组件间距",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "沿水平方向布局的容器，可设置子组件间距",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈，后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Tabs",
      "purpose": "通过页签进行内容视图切换的容器组件",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "仅在Tabs中使用，对应一个切换页签的内容视图",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Navigation",
      "purpose": "路由导航的根视图容器，作为Page页面的根容器使用",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "NavRouter",
      "purpose": "导航组件，默认提供点击响应处理（已停止维护）",
      "anchor": "navrouter",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，在容器主轴方向上自动填充容器空余部分",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "提供分割线组件，分割不同内容块/内容元素",
      "anchor": "divider",
      "status": "found"
    }
  ],
  "notableFindings": [
    "NavRouter 从 API version 13 开始已停止维护，推荐使用 NavPathStack 配合 navDestination 属性进行页面路由",
    "Flex 组件在渲染时存在二次布局过程，性能敏感场景建议使用 Column/Row 替代",
    "Blank 仅在父容器为 Row/Column/Flex 且父容器设置了主轴大小时才会自动拉伸填充",
    "Tabs 仅支持 TabContent 作为直接子组件（if/else 和 ForEach 渲染控制下的 TabContent 也支持）",
    "所有组件均为 ArkUI 系统内置组件，无需额外 import 语句"
  ],
  "missingApis": []
}

{
  "module": "02-controls.md",
  "group": "02 — Controls, Input & Dialogs",
  "apiCount": 13,
  "apis": [
    {
      "name": "Button",
      "purpose": "按钮组件，可快速创建不同样式的按钮",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "TextInput",
      "purpose": "单行文本输入框组件",
      "anchor": "textinput",
      "status": "found"
    },
    {
      "name": "TextArea",
      "purpose": "多行文本输入框组件，自动换行显示",
      "anchor": "textarea",
      "status": "found"
    },
    {
      "name": "Checkbox",
      "purpose": "提供多选框组件",
      "anchor": "checkbox",
      "status": "found"
    },
    {
      "name": "Select",
      "purpose": "提供下拉选择菜单，让用户在多个选项间选择",
      "anchor": "select",
      "status": "found"
    },
    {
      "name": "DatePicker",
      "purpose": "滑动选择日期的组件",
      "anchor": "datepicker",
      "status": "found"
    },
    {
      "name": "TimePicker",
      "purpose": "滑动选择时间的组件",
      "anchor": "timepicker",
      "status": "found"
    },
    {
      "name": "AlertDialog",
      "purpose": "显示警告弹窗组件，可设置文本内容与响应回调",
      "anchor": "alertdialog",
      "status": "found"
    },
    {
      "name": "CustomDialog",
      "purpose": "通过CustomDialogController类显示自定义弹窗，支持完全自定义样式与内容",
      "anchor": "customdialog",
      "status": "found"
    },
    {
      "name": "ActionSheet",
      "purpose": "列表弹窗，提供多个选项供用户选择",
      "anchor": "actionsheet",
      "status": "found"
    },
    {
      "name": "Menu",
      "purpose": "以垂直列表形式显示的菜单，需配合bindMenu/bindContextMenu使用",
      "anchor": "menu",
      "status": "found"
    },
    {
      "name": "Toggle",
      "purpose": "提供勾选框样式、状态按钮样式和开关样式",
      "anchor": "toggle",
      "status": "found"
    },
    {
      "name": "Radio",
      "purpose": "单选框，提供相应的用户交互选择项",
      "anchor": "radio",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Button、TextInput、TextArea、Checkbox、Select、DatePicker、TimePicker、Toggle、Radio 均为 ArkUI 内置组件（ArkTS Component），无需 import 语句，可直接在 build() 中使用",
    "AlertDialog 和 ActionSheet 推荐通过 getUIContext().showAlertDialog() / getUIContext().showActionSheet() 调用以避免 UI 上下文不明确问题",
    "CustomDialog 需使用 @CustomDialog 装饰器装饰 struct，并通过 CustomDialogController 管理生命周期",
    "Menu 组件不能单独使用，必须配合宿主组件的 bindMenu 或 bindContextMenu 属性挂载",
    "Checkbox 从 API 11 开始默认样式从圆角方形变为圆形",
    "Radio 从 API 12 开始默认选中样式从 DOT 变为 TICK",
    "Button API 18 起 ButtonType 默认值从 Capsule 变更为 ROUNDED_RECTANGLE"
  ],
  "missingApis": []
}

{
  "module": "03-list.md",
  "group": "03 — List, Scroll & Data Display",
  "apiCount": 10,
  "apis": [
    {
      "name": "List",
      "purpose": "列表容器，连续多行呈现同类数据（图片和文本），支持懒加载和预加载",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "ListItem",
      "purpose": "列表具体项，必须配合 List 或 ListItemGroup 使用，支持滑动操作",
      "anchor": "listitem",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件，子组件布局尺寸超过父组件尺寸时内容可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "ForEach",
      "purpose": "基于数组数据的循环渲染，需与容器组件配合使用",
      "anchor": "foreach",
      "status": "found"
    },
    {
      "name": "LazyForEach",
      "purpose": "按需迭代数据并创建组件，滑出可视区域时销毁回收以降低内存占用",
      "anchor": "lazyforeach",
      "status": "found"
    },
    {
      "name": "Badge",
      "purpose": "信息标记组件，可附加在单个组件上用于信息提醒",
      "anchor": "badge",
      "status": "found"
    },
    {
      "name": "Swiper",
      "purpose": "滑块视图容器，提供子组件滑动轮播显示的能力，支持自动播放和指示器",
      "anchor": "swiper",
      "status": "found"
    },
    {
      "name": "Image",
      "purpose": "图片组件，支持 png/jpg/svg/webp/gif/heif/tiff 格式，支持本地和网络图片",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "文本显示组件，支持 Span/ImageSpan 子组件实现图文混排",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "Counter",
      "purpose": "计数器组件，提供增加/减少的计数操作，支持 onInc/onDec 事件",
      "anchor": "counter",
      "status": "found"
    }
  ],
  "notableFindings": [
    "所有组件均为 ArkUI 内置组件/渲染控制语句，无需 import 导入",
    "LazyForEach 优于 ForEach：大量数据场景下按需创建/销毁组件，推荐在 List、Swiper 等容器中使用",
    "ForEach 会一次性加载所有数据并创建全部子组件，在数据量较大时可能影响性能",
    "Scroll 嵌套 List 且滚动方向相同时，若 List 不设宽高会导致懒加载失效",
    "Image 使用网络图片时需申请 ohos.permission.INTERNET 权限",
    "List 组件从 API version 7 开始支持，所有组件支持在元服务中使用（API 11+）"
  ],
  "missingApis": []
}

{
  "module": "04-state.md",
