      "purpose": "装饰@Observed类对象属性以实现嵌套响应",
      "anchor": "@objectlink",
      "status": "missing"
    },
    {
      "name": "@StorageLink",
      "purpose": "与AppStorage建立双向数据绑定",
      "anchor": "@storagelink",
      "status": "found"
    },
    {
      "name": "@LocalStorageLink",
      "purpose": "与LocalStorage实例建立双向数据绑定",
      "anchor": "@localstoragelink",
      "status": "found"
    },
    {
      "name": "@Observed",
      "purpose": "类装饰器，使类属性变化可被监听",
      "anchor": "@observed",
      "status": "missing"
    },
    {
      "name": "PersistentStorage",
      "purpose": "持久化AppStorage属性到本地文件",
      "anchor": "persistentstorage",
      "status": "found"
    },
    {
      "name": "Environment",
      "purpose": "查询系统环境变量并存入AppStorage",
      "anchor": "environment",
      "status": "found"
